  ('E-handel (Start / Plus / Pro)', 'E-commerce (Start / Plus / Pro)', 'E-commerce (Start / Plus / Pro)', $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Vad det är: "}, {"type": "text", "text": "En webbutik på vår egen plattform med eget CMS, i tre nivåer."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Passar för: "}, {"type": "text", "text": "Företag som vill sälja produkter online – nivå efter sortiment och behov."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Start: "}, {"type": "text", "text": "Från 19 000 kr + 1 490 kr/mån: ~100 produkter, Klarna/Stripe, frakt, mobilanpassning och grundläggande SEO."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Plus: "}, {"type": "text", "text": "Från 35 000 kr + 2 490 kr/mån: ~1 000 produkter, rabattkoder, kundkonton, nyhetsbrev och on-page SEO. Populärast."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pro: "}, {"type": "text", "text": "Från 59 000 kr + 4 900 kr/mån: obegränsat antal produkter, ERP-integration (Fortnox/Visma), B2B-priser, lager i realtid, flera språk och valutor samt SLA-support."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "FAQ: "}, {"type": "text", "text": "\"Kan vi byta nivå?\" Ja, uppgradera när ni växer. \"Integreras med vårt affärssystem?\" Ja, på Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Säljtips: "}, {"type": "text", "text": "Matcha nivå mot antal produkter och integrationsbehov. Tillägg: ERP-integration samt extra språk och valuta."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Avgränsning: "}, {"type": "text", "text": "Egen plattform (inte Shopify eller Woo) – vi sköter driften."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "What it is: "}, {"type": "text", "text": "An online store on our own platform with its own CMS, in three tiers."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Who it's for: "}, {"type": "text", "text": "Companies that want to sell products online – tier by range and needs."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Start: "}, {"type": "text", "text": "From SEK 19,000 + SEK 1,490/mo: ~100 products, Klarna/Stripe, shipping, mobile-friendly and basic SEO."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Plus: "}, {"type": "text", "text": "From SEK 35,000 + SEK 2,490/mo: ~1,000 products, discount codes, customer accounts, newsletters and on-page SEO. Most popular."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pro: "}, {"type": "text", "text": "From SEK 59,000 + SEK 4,900/mo: unlimited products, ERP integration (Fortnox/Visma), B2B pricing, real-time stock, multiple languages and currencies, and SLA support."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "FAQ: "}, {"type": "text", "text": "\"Can we change tier?\" Yes, upgrade as you grow. \"Does it integrate with our business system?\" Yes, on Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Sales tips: "}, {"type": "text", "text": "Match the tier to the number of products and integration needs. Add-ons: ERP integration and extra language and currency."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Scope: "}, {"type": "text", "text": "Our own platform (not Shopify or Woo) – we handle the operations."}]}]}$j$::jsonb, $j${"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Qué es: "}, {"type": "text", "text": "Una tienda online en nuestra propia plataforma con CMS propio, en tres niveles."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Para quién: "}, {"type": "text", "text": "Empresas que quieren vender productos online: nivel según catálogo y necesidades."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Start: "}, {"type": "text", "text": "Desde 19 000 SEK + 1 490 SEK/mes: ~100 productos, Klarna/Stripe, envíos, adaptación a móvil y SEO básico."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Plus: "}, {"type": "text", "text": "Desde 35 000 SEK + 2 490 SEK/mes: ~1 000 productos, códigos de descuento, cuentas de cliente, newsletters y SEO on-page. El más popular."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Pro: "}, {"type": "text", "text": "Desde 59 000 SEK + 4 900 SEK/mes: productos ilimitados, integración ERP (Fortnox/Visma), precios B2B, stock en tiempo real, varios idiomas y monedas, y soporte SLA."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Preguntas frecuentes: "}, {"type": "text", "text": "\"¿Podemos cambiar de nivel?\" Sí, ampliad al crecer. \"¿Se integra con nuestro sistema de gestión?\" Sí, en Pro."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Consejos de venta: "}, {"type": "text", "text": "Ajusta el nivel al número de productos y a las necesidades de integración. Extras: integración ERP e idioma y moneda adicionales."}]}, {"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "bold"}], "text": "Alcance: "}, {"type": "text", "text": "Plataforma propia (no Shopify ni Woo): nosotros nos encargamos de la operación."}]}]}$j$::jsonb, 10)
) AS v(title, title_en, title_es, body, body_en, body_es, ord)
JOIN public.training_categories cat ON cat.slug = 'produktkunskap'
WHERE NOT EXISTS (
  SELECT 1 FROM public.training_items ti
  WHERE ti.category_id = cat.id AND ti.title = v.title
);
